import React, { useState, useEffect } from "react";
import "./Typewriter.css";

const Typewriter = ({ text, baseDelay = 10 }) => {
  const [displayedText, setDisplayedText] = useState("");
  const [index, setIndex] = useState(0);

  useEffect(() => {
    if (index < text.length) {
      const delay = baseDelay + Math.random() * 150;
      const timer = setTimeout(() => {
        setDisplayedText((d) => d + text.charAt(index));
        setIndex((prevIndex) => prevIndex + 1);
      }, delay);

      return () => clearTimeout(timer);
    }
  }, [index, text, baseDelay]);

  useEffect(() => {
    const topElement = document.querySelector(".top-element");
    const lowerElement = document.querySelector(".lower-element");

    // Function to trigger bounce effect
    function triggerBounce() {
      if (topElement) {
        console.log("Bounce triggered"); // Add this log to check if the function is being called
        topElement.classList.add("bounce");
        setTimeout(() => {
          topElement.classList.remove("bounce");
          console.log("Bounce class removed"); // Check when the class is removed
        }, 600); // Match the bounce animation duration
      }
    }

    // Check if lowerElement exists
    if (!lowerElement) {
      console.error("Lower element not found!");
      return;
    }

    // Use MutationObserver to detect style changes (like height changes)
    const observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        if (mutation.attributeName === "style") {
          const newHeight = lowerElement.offsetHeight;
          console.log("Lower element height changed:", newHeight);
          triggerBounce();
        }
      });
    });

    // Start observing the lower element for style changes
    observer.observe(lowerElement, {
      attributes: true, // Observe attribute changes
      attributeFilter: ["style"], // Specifically observe the style attribute
    });

    // Cleanup observer on unmount
    return () => {
      observer.disconnect();
    };
  }, []);

  return (
    <div>
      <img
        className="profile-img top-element"
        src="profile.jpg"
        alt="profile"
      />
      <h1>Hey, I'm Adam :)</h1>

      <div className="typewriter lower-element">
        {displayedText}
        <span className="caret">|</span>
      </div>
    </div>
  );
};

export default Typewriter;
